const Q_COMMERCE_2016=[{"id": "objective>Commerce>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ancillary to trade that it easily links suppliers and consumers is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tourism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">banking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communication is the means of sending and receiving information from one place to another. Suppliers and customers can be easily linked together through communication services e.g telephone, telex, internet/e-mail etc. The development of telecommunications system has also eased and hastened contacts between people within commercial centres and all over the world.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence for the payment of goods under a COD system is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">delivery → e-payment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">delivery → cash payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash payment → delivery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">e-payment → delivery</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cash on Delivery (COD) is a term of payment in which the purchaser is expected to pay for the goods through the post master immediately they are delivered to him. This is a service provided by the post office and is common in mail under business  <br/>  delivery → Cash payment.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general acceptability of money as a standard of value is used to explain its function as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">store of value </div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basis of adjustment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard for deferred payment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While the unit of account is the precise term for the general acceptability of money as a standard of value, the medium of exchange is a function that inherently relies on the acceptability of money. Money must be accepted widely to function effectively as a medium of exchange, facilitating the buying and selling of goods and services.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Commerce>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major setback of international trade is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">devaluation of currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate appreciation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic sanctions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International trade can be negatively affected by 'economic sanctions'. Economic sanctions are commercial and financial penalties applied by one or more countries against a targeted self-governing state, group, or individual. These sanctions can limit a country's ability to trade internationally, thus posing a major setback.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document issued to a ports authority when goods are deposited is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dock warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dock landing account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of sight </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dock warrant is a receipt for goods delivered and stored in the warehouse. It entitles the holder to take possession of goods. It is also known as dock receipt. This document will state that goods have been kept in the warehousing by the owner awaiting clearing or loading.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION"}, {"id": "objective>Commerce>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organization that issues a cheque to cover the salaries of its employees is using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a standing order of payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank order of crediting account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an overdraft system of payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a credit transfer system of payment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an organization issues a cheque to cover the salaries of its employees, it is using a credit transfer system of payment. This is because the organization is transferring funds from its account to the accounts of its employees. A credit transfer is a deposit of funds directly into a bank account using electronic means.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of its function of a retailer is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">financing of production activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breaking of bulk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of jobs for customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of credit facilities to relations </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The retailer engages in breaking of goods into smaller units for the customers. By this, he enables the customers to buy in any amount. The retailer is a trader who buys goods in small quantity from the wholesaler and sells in units to the final consumers.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> From the diagram above, what does <strong>I</strong> stand for?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Home trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Publicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aids to trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advertising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The divisions of commerce Trade and  Aids to trade or ancillaries to trade. Aids to trade are the commercial activities which facilitate trade (buying and selling) i.e they make trade possible. Aids to trade are banking, insurance, transport, advertising, warehousing, communication and tourism. </div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major determinants of the volume of production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the availability of banks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the market size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex distribution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The size of the market is a major determinant of the volume of production. The size of the market refers to the demand for goods produced. The greater the greater; the volume of production and vice-versa. A large market usually have high demand for goods than a small market.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gilt-edged securities are issued mainly by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-governmental organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multi-national companies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gilt-edged security is a security issued by the government; it has a fixed rate of interest. This type of security is considered to be very safe as government cannot fail to pay its debts. Gilt edge carries a minimum issued risks in terms of repayment.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A software application which enables a user to display and interact with texts, images and videos is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">web browser </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internet protocol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corel draw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">web server</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The web browser is a software application for retrieving, presenting and traversing information resources on the world wide web.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the factors affecting the growth of commerce in West Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the emergence of specialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political instability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government intervention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the role of advertising </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political instability in the area of constant change of government and war have hindered investment in West Africa. Foreign investors are afraid to invest in the sub-region for example, the Boko Haram Insurgent group and the Niger Delta Avengers are a case in point that have limited the growth of commerce in West Africa.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of small-scale retailers over large -scale retailers is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is personal relationship with customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is absence of credit transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is no personal relationship with customers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it requires huge capital to set up</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Small-scale retailers are those trader that sell goods in small units to the final consumers. Little capital can be used to set up small scale retailing such as Hawking, Mobile Shops, Kiosks etc have been known to have one-on-one contact with the customers, thus bringing about personal relationship with the customers.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical components of a computer system are commonly referred to as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">system unit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardware</div>", "<div style=\"font-family:Cambria;font-size:17px;\">software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compact disk</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hardware refers to the physical parts of a computer and it includes computer case, monitor, keyboard etc.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Services rendered to the public is provided by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">domestic servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">professionals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">civil servants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government is charged with the responsibility of rendering services to the public through the tax paid by the citizens. Such services include Health Care, Education, Good roads, pipe borne water, Electricity among others.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a computer operating system is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Microsoft Word 2000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Word Prefect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Pagemaker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Windows 2000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An operating system is a system software that manages computer hardware, software resources, and provides various services for computer programs. Windows 2000 is an example of an operating system. Microsoft Word 2000, The Word Prefect, and The Pagemaker are all application software, not operating systems.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shop with many stores trading under a single roof which stocks varieties of goods with separate unit heads is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supermarket</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple shop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superstore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">departmental store</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Departmental store is a collection of shops under one roof with ownership of each shop or department specialising in selling a special range of goods. Each department normally buys separately, exercise its own stock control and sets its own product policy. It is also a large retailing unit handling a wide variety of shopping and specialty goods but organised into separate departments for the purpose of promotion, service and control. There is high degree of departmentalisation e.g Kingsway stores and Leventis stores.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document that indicates the type of shares available for sale to the public is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a prospectus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a closed indent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an open indent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A prospectus is an invitation to the public to purchase shares or debentures. It is most often issued by public limited companies. A prospectus gives detailed information about the promoters and directors of a particular company. The document contains reports by the company's auditors, regarding past profits, losses and dividends declared. </div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Microprocessor is an electronic circuit that functions as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">random access money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">central processing unit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transmission protocol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">file transfer protocol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Microprocessor is an electronic Unit which incorporates the functions of a computer CPU on a single integrated circuit (IC) or at most a few integrated circuits.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To meet security requirements before gaining access to data, a computer operator supplies</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a modem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a password</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a yahoo address</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an e-mail address</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A password is a security that protects the computer from unknown users. It enables only the user to have access to the computer.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The environment hazard that is most difficult to control is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political unrest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air pollution is the emission of harmful substances into the atmosphere. Air pollution destroys the environment and is one of the causes of various forms of diseases such as cancer. Industries, cars, domestic household constitute a large percentage of emission of gases into the atmosphere. Examples as Green house gases, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> Emission and Carbon (IV)oxide are some of the gases emitted into the atmosphere.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : POLLUTION"}, {"id": "objective>Commerce>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Low cost of maintenance is one of the merits of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pipeline transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road transportation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pipeline transportation is known for its low cost of maintenance. This is because once the pipeline is laid, the cost of maintaining it is relatively low compared to other modes of transportation like road, air, and water.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION"}, {"id": "objective>Commerce>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of turnover of a firm in a given year is 5 times while the average stock is ₦12,500. What is the turnover of the firm?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦24,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦62,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦46,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦65,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Turnover or sales refers to the total value of net sales of a business during a particular period. Rate of turnover on the other hand is the number of times the average stock is turned over. The rate of turnover is computed thus:  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.O.T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">cost of good sold<hr size=\"1\" />average stock</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">where</td><td style=\"text-align:center;\">Average stock</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">closing stock + Opening stock<hr size=\"1\" />2</td></tr></table></div>  <br/>  Turnover of firm = Average stock × rate of turnover  <br/>  = ₦12,500 × 5  <br/>  = ₦62,500</div>", "topic": "FINANCING BUSINESS : TURNOVER"}, {"id": "objective>Commerce>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes the bill of lading?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A document acknowledging shipment of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A document of title to the goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An evidence of receipt of the goods on board</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An evidence of payment of custom duties </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bill of lading is a document of title giving the holder a right to take possession of the goods to which it refers. A bill of lading is a contract of carriage of goods between an exporter and the shipping company. It is issued out by a shipping company's official as a receipt for the goods shipped and at the same time undertakes to carry the goods to the port of destination. A bill of lading is a document of title. It is made out in triplicates, one copy being retained by the exporter, the second by the ship master while the third is sent to the importer.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION"}, {"id": "objective>Commerce>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial activities in Nigeria have greatly been enhanced due to improvement in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warehousing activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insurance activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communication network</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial activities in Nigeria have been greatly enhanced due to improvements in the transportation system. This is because transportation plays a crucial role in commerce as it allows for the movement of goods from places of production to the market and also facilitates the movement of consumers. Improved transportation system means goods and services can reach the market in a timely and efficient manner, thus enhancing commercial activities.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The arrangement and interrelationship of the various components and positions of a business is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unity of direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clarity of objective</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizational structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organisation structure shows the flow of responsibilities, authority and channels of communication. It is an arrangement and interrelationship of the various component parts and positions of a business. </div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slogan, <em>a wonderful world </em>, used by a communication network is a form of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">packaging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">persuasive advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product differentiation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A wonderful world is a form of persuasive advertising defined as advertising which tries to persuade customers to buy a particular brand of a product as being different from other brands persuasive advertising, which is emotional in nature, is used to induce or arouse customer's interest in order to persuade them to buy a particular product.</div>", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The variety of goods and services which a company offers for sale is its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">product mix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion mix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price mix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">place mix</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Product mix is concerned with developing the right product for the target market. The crux of the matter is to develop something which will satisfy the consumers' needs marketing mix determines the products line, assortment, designs, differential, branding, labelling and packaging, product line, assortment, designs, differential, branding, labelling and packaging, product additions, modifications and deletions, durability, quality and style variation. </div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document authorizing one to transact business outside the country is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">import license</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dock warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">export license</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An export license is a government document that authorizes the export of specific goods in specific quantities to a particular destination.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The managerial ability of a supervisor in an organization may be under utilized if the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">morale of the supervised is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control is wide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morale of the supervised is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control is narrow</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The span of control refers to the number of subordinates that a manager or supervisor can efficiently and effectively direct. If the span of control is too narrow, it means the manager supervises few subordinates. This can lead to underutilization because the managers capacity to manage more subordinates is not fully utilized.  <br/> </div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major parties to an agency relationship are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">principal and the agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bailee and the bailor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">principal and the creditors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholder and the creditor </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An agency can be defined as a legal relationship that exist between two parties, when one called the agent is employed by another called \"the principal\" to bring the principal into a legal relationship with the third party.  <br/> An agent is a person who is given authority by the principal to enter into a contract on his behalf.</div>", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT"}, {"id": "objective>Commerce>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important factor that influences the location of cement industry in an area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attitude of individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political interest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skill and training</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cement industry is an example of localization of industry defined as the concentration of many firms of an industry in a particular place due to the presence of certain factors. The availability of natural endowment is crucial in the location of an industry as this will help to provide the needed raw materials for its operations.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term PLC implies that the shares are available</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">publicly on the stock exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privately on the stock exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to the public at the company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicly in commercial banks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">PLC stands for Public Limited Company. This implies that the shares of the company are available publicly on the stock exchange. This means that members of the public can buy shares in the company.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The application of division of labour should generally bring about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in the variety of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the quantity of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheapness of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost efficiency in the production of goods and services</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The division of labour is the specialization of cooperating individuals who perform specific tasks and roles.</div>", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Commerce>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On liquidation of a public limited liability company, the residual owners are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creditors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preference shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary shareholders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of a company's liquidation, after all debts and obligations have been paid, any remaining assets or profits are distributed to the ordinary shareholders. Therefore, they are considered the residual owners.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Production involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">changing the form of goods, moving and making them available as needed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making goods available where and when needed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the manufacturing of goods and provisions of services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the assembling of all necessary parts to produce a finished product</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing of goods is the process of converting raw materials into finished products through various methods such as machining, assembling, and packaging. <br/>  <br/> Also the provision of services activities provide tangible products, such as healthcare, education, and entertainment, which do result in physical product but fulfill a need or demand.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is both merit and demerit in partnership?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The bearing of risk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its unlimited nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The number of partners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The withdrawal of a major partner</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Having multiple partners can bring in a variety of skills, expertise, and capital, which can benefit the business by enhancing decision-making, expanding resources and sharing responsibilities. <br/>  <br/> On the other hand, having many partners can also lead to conflicts, slower decision making processes, and potential disagreements. Managing the interests and contributions of multiple partners can be challenging and may complicate the administration of partnership.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the collapse of a business enterprise, the person appointed to dispose asset is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a broker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auctioneer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a liquidator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auditor</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A liquidator is the person appointed to sell off a collapsed firm assets in order to settle its creditor�s or share holders.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Entrusting the management of a company to the courts to enable the settlement of the company's obligations is an indication of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bankruptcy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bankruptcy is a legal process in which a person or company is unable to pay back their debts. When a company is in bankruptcy, the court may appoint a trustee to manage the company's assets and distribute them to the company's creditors.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The financial instrument for borrowing in which the collateral is usually more than the amount borrowed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trust certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detachable warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortgage bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convertible securities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mortgage bond is the financial instrument on properties which are always more than amount to be borrowed: <br/> </div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organizational structure that relates the positions of specialists to the  <br/> line managers is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">line structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">staff structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line and staff structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Line and staff structure is an organizational structure that combines the direct flow of authority from the top level to the lower level (line structure) with staff departments that support the line departments. The staff departments provide advice (expertise, legal counsel, etc.) to line managers who make the decisions.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wholesaler who possesses the title to the goods he sells is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a merchant wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a general wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an agent wholesaler</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A merchant wholesaler is a wholesaler who takes title to goods and carries risks associated with ownership. They buy goods from manufacturers and sell them to businesses, government agencies, other wholesalers or retailers. They take ownership of the goods and assume the risk associated with carrying inventory.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important principle of a good organizational structure is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ideal standard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clarity of mission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequacy of resources</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The span of control is a key principle of a good organizational structure. It refers to the number of subordinates that a manager or supervisor can effectively manage. This number varies with the type of work and complexity of tasks. Too many subordinates per manager can lead to inefficiency and loss of control, while too few can lead to over-supervision and lack of empowerment.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company that is registered with the Corporate Affairs Commission only without being enlisted on the Stock Exchange is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public liability company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint venture company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">registered company</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A company that is registered with the Corporate Affairs Commission only without being enlisted on the Stock Exchange is a registered company. This means that the company has been legally recognized by the government but is not publicly traded on the stock exchange.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic function of the Nigerian Ports Authority is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that the right caliber of personnel is employed at the ports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinates and regulates the activities of shipping line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitates and controls the movement of goods and services into and out of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinates the activities of all the seaports in the country</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Port Authority provides facilities at the port to ensure effective and efficient sea transportation. The functions of NPA are: <br/> - Provision of facilities <br/> - Maintenance and improvement of port <br/> - revenue collection <br/> - provision of warehouse <br/> - supervision of loading and off loading of goods.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept that refers to the sale, transfer or exchange of goods and services is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tariff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept that refers to the sale, transfer or exchange of goods and services is 'trade'. Trade involves the transfer or exchange of goods and services from person or entity to another, often in exchange for money. A system or network that allows trade is called a market. Therefore, the correct answer is 'trade'.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A guarantee given by one person or party to another in which the integrity  <br/> of the person is assured is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fidelity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">term assurance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subrogation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indemnity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A guarantee given by one person or party to another in which the integrity of the person is assured is 'fidelity'. Fidelity refers to the degree of exactness with which something is copied or reproduced. In this context, it refers to the assurance or guarantee of the integrity or truthfulness of a person or party. Therefore, the correct answer is 'fidelity'.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The firm that adapts itself to deliver the desired satisfaction more effectively and efficiently than its competitors is said to be practising</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing concept</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marketing concept is a process when a company plans and implements to maximize profit by increasing sales, satisfying customer's needs and beating competitors. The purpose is to create a situation that benefits both parties; customer and the company.</div>", "topic": "ELEMENT OF MARKETING : THE MARKETING CONCEPT"}, {"id": "objective>Commerce>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The payment made periodically in respect of an insurance policy entered into is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrender value</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The payment made periodically in respect of an insurance policy is known as a premium. This is the amount that the policyholder must pay in exchange for the coverage provided by the insurer. The premium is usually paid on a regular basis, such as monthly, quarterly, or annually.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of major features of a line organizational structure is that it..</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allows responsibility to flow upwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allows authority to flow upwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gives the line managers limited authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gives the subordinates unlimited authority</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major features of a line organizational structure is that it allows authority to flow upwards. In a line organizational structure, authority flows in a direct line from the top of the organizational hierarchy to the bottom. This means that each person in the organization has a single superior from whom they receive orders and to whom they are responsible.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}];
